import { React, useState } from 'react'
import Button from '@mui/material/Button';
import { FormControl, FormLabel, Stack, Box, TextField, InputLabel, Input, IconButton, InputAdornment } from '@mui/material';
import Visibility from '@mui/icons-material/Visibility';
import VisibilityOff from '@mui/icons-material/VisibilityOff';
import styled from '@emotion/styled'
import { Link, Navigate, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import supabaseClient from '../supabase'
import appTheme from '../theme';



const LoginForm = () => {
    
    const [showPassword, setShowPassword] = useState(false);
  
    const handleClickShowPassword = () => setShowPassword((show) => !show);
  
    const handleMouseDownPassword = (event) => {
      event.preventDefault();
    };

    const { user, setUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await supabaseClient.auth.signInWithPassword(user.email, user.password)
            
            navigate('/')

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            <Stack sx={{
                    display: 'flex',
                    alignItems: 'center',
                }}>

                    <Box sx={{
                            margin: '5rem auto',
                            padding: '1rem',
                        }}>
                        <TextField label="Email" variant="standard" sx={{
                            width: '100%',
                            paddingBottom: '2rem',
                            color: appTheme.palette.primary.main,
                            
                        }}
                        InputLabelProps={{
                            style: {
                                fontSize: '14px',
                                color: appTheme.palette.primary.main,
                            }
                        }}
                        inputProps={{
                            style: {
                                borderBottom: '1px solid #779A4A',
                                disableUnderline: true
                            },
                        }}/>
                        <FormControl sx={{ m: 1, width: '100%' }} variant="standard">
                        <InputLabel htmlFor="standard-adornment-password">Password</InputLabel>
                        <Input
                            id="standard-adornment-password"
                            type={showPassword ? 'text' : 'password'}
                            endAdornment={
                            <InputAdornment position="end">
                                <IconButton
                                aria-label="toggle password visibility"
                                onClick={handleClickShowPassword}
                                onMouseDown={handleMouseDownPassword}
                                >
                                {showPassword ? <VisibilityOff /> : <Visibility />}
                                </IconButton>
                            </InputAdornment>
                            }
                        />
                        </FormControl>
                    </Box>
                    
                    <Button variant="contained" sx={{
                        textTransform: 'capitalize',
                        fontSize: '18px',
                        fontFamily: 'Poppins',
                        fontWeight: 700,
                        width: '100%',
                        marginTop: '6rem',
                        marginBottom: '1rem'
                    }}>Ingresar</Button>
            </Stack>            
}
        </>
  )
}

export default LoginForm
